#!/bin/bash
set -euo pipefail
DEPLOYMENT=${1:?Usage: create-hpa.sh <deployment> [min] [max] [cpu-target]}
MIN=${2:-3}
MAX=${3:-20}
CPU=${4:-70}
NS=${KUBE_NAMESPACE:-default}

echo "Creating HPA for $DEPLOYMENT (min=$MIN, max=$MAX, CPU target=${CPU}%)"
kubectl autoscale deployment "$DEPLOYMENT" \
  --min="$MIN" \
  --max="$MAX" \
  --cpu-percent="$CPU" \
  -n "$NS"

echo ""
kubectl get hpa -n "$NS"
echo ""
echo "Monitor with: kubectl get hpa -n $NS -w"
